#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 0
#endif

inline class_T bench_value(__global class_T* data, size_t idx, class_T seed) {
  class_T src = data[idx] + seed - seed;

  class_T f0 = src;
  class_T f1 = src;
  class_T f2 = src;
  class_T f3 = src;
  class_T f4 = src;
  class_T f5 = src;
  class_T f6 = src;
  class_T f7 = src;

  class_T t0 = src;
  class_T t1 = src;
  class_T t2 = src;
  class_T t3 = src;
  class_T t4 = src;
  class_T t5 = src;
  class_T t6 = src;
  class_T t7 = src;

  for (int j = 0; j < (COMPUTE_ITERATIONS / 8); ++j) {
    t0 = t0 * t0 + f0;
    t1 = t1 * t1 + f1;
    t2 = t2 * t2 + f2;
    t3 = t3 * t3 + f3;
    t4 = t4 * t4 + f4;
    t5 = t5 * t5 + f5;
    t6 = t6 * t6 + f6;
    t7 = t7 * t7 + f7;
  }

#if (COMPUTE_ITERATIONS % 8) > 0
  t0 = t0 * t0 + f0;
#endif
#if (COMPUTE_ITERATIONS % 8) > 1
  t1 = t1 * t1 + f1;
#endif
#if (COMPUTE_ITERATIONS % 8) > 2
  t2 = t2 * t2 + f2;
#endif
#if (COMPUTE_ITERATIONS % 8) > 3
  t3 = t3 * t3 + f3;
#endif
#if (COMPUTE_ITERATIONS % 8) > 4
  t4 = t4 * t4 + f4;
#endif
#if (COMPUTE_ITERATIONS % 8) > 5
  t5 = t5 * t5 + f5;
#endif
#if (COMPUTE_ITERATIONS % 8) > 6
  t6 = t6 * t6 + f6;
#endif

  return t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7;
}

__kernel void benchmark_func(class_T seed, __global class_T* data) {
  const size_t gid = get_global_id(0);

#ifdef BLOCK_STRIDED
  const size_t lid = get_local_id(0);
  const size_t lsize = get_local_size(0);
  const size_t group = get_group_id(0);
  const size_t base =
      group * (size_t)(lsize * ELEMENTS_PER_THREAD * FUSION_DEGREE) + lid;
  const size_t stride = lsize;
#else
  const size_t base = gid;
  const size_t stride = get_global_size(0);
#endif

  for (size_t fusion = 0; fusion < (size_t)FUSION_DEGREE; ++fusion) {
    const size_t fusion_base =
        base + fusion * (size_t)ELEMENTS_PER_THREAD * stride;

    for (size_t elem = 0; elem < (size_t)ELEMENTS_PER_THREAD; ++elem) {
      const size_t idx = fusion_base + elem * stride;
      data[idx] = bench_value(data, idx, seed);
    }
  }
}
